17	export function scaleNumber(
18	  value: number,
19	  domainMin: number,
20	  domainMax: number,
21	  rangeMin: number,
22	  rangeMax: number,
23	): number {
24	  if (domainMax === domainMin) {
25	    return (rangeMin + rangeMax) / 2;
